using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string text, int maxSentences);
}

/// <summary>
/// Extractive summarizer that scores sentences by word frequency
/// and returns the top-ranked ones in their original order.
/// </summary>
public partial class DocumentSummarizer : IDocumentSummarizer
{
    private static readonly char[] s_sentenceDelimiters = ['.', '!', '?'];
    private static readonly HashSet<string> s_stopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","in","on","at",
        "to","for","of","with","by","it","this","that","from","as","be","has",
        "had","have","not","no","do","does","did","will","would","can","could",
        "should","may","might","so","if","then","than","its","i","you","he",
        "she","we","they","me","him","her","us","them","my","your","his","our",
        "their","what","which","who","whom","how","when","where","why"
    };

    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);
        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = sentences
            .Select((s, i) => (Index: i, Sentence: s, Score: ScoreSentence(s, wordFrequencies)))
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .OrderBy(x => x.Index) // preserve original order
            .Select(x => x.Sentence);

        return string.Join(" ", scored);
    }

    private static List<string> SplitSentences(string text)
    {
        var raw = text.Split(s_sentenceDelimiters, StringSplitOptions.RemoveEmptyEntries);
        var sentences = new List<string>();
        int pos = 0;

        foreach (var segment in raw)
        {
            var trimmed = segment.Trim();
            if (trimmed.Length == 0)
                continue;

            // Re-attach the original delimiter
            pos = text.IndexOf(trimmed, pos, StringComparison.Ordinal);
            int end = pos + trimmed.Length;
            char delimiter = end < text.Length && s_sentenceDelimiters.Contains(text[end])
                ? text[end]
                : '.';

            sentences.Add(trimmed + delimiter);
            pos = end;
        }

        return sentences;
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in TokenizeWords(sentence))
            {
                if (s_stopWords.Contains(word) || word.Length < 2)
                    continue;
                freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }
        return freq;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> frequencies)
    {
        var words = TokenizeWords(sentence).Where(w => !s_stopWords.Contains(w) && w.Length >= 2).ToList();
        if (words.Count == 0) return 0;
        return words.Sum(w => frequencies.GetValueOrDefault(w)) / (double)words.Count;
    }

    private static IEnumerable<string> TokenizeWords(string text)
        => WordPattern().Matches(text).Select(m => m.Value);

    [GeneratedRegex(@"\b[a-zA-Z0-9]+\b")]
    private static partial Regex WordPattern();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizer _summarizer;

    public SummarizeController(IDocumentSummarizer summarizer)
    {
        _summarizer = summarizer;
    }

    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

